const request = $('ClubSpark Import Form Webhook').first()?.json ?? $input.first()?.json ?? {};
const headers = request.headers ?? {};
const clean = (value) => value === null || value === undefined ? '' : String(value).trim();
const escapeHtml = (value) => String(value ?? '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/\"/g, '&quot;')
  .replace(/'/g, '&#39;');
const deriveBaseUrl = (headers, fallback) => {
  const forwardedProto = clean(headers['x-forwarded-proto']);
  const forwardedHost = clean(headers['x-forwarded-host']);
  const host = forwardedHost || clean(headers.host);
  const forwardedPort = clean(headers['x-forwarded-port']);
  if (!host) return fallback;
  const proto = forwardedProto || 'http';
  let authority = host;
  if (forwardedPort && !authority.includes(':')) {
    const isDefaultPort = (proto === 'http' && forwardedPort === '80') || (proto === 'https' && forwardedPort === '443');
    if (!isDefaultPort) authority = `${authority}:${forwardedPort}`;
  }
  return `${proto}://${authority}`;
};
const fallbackBaseUrl = 'http://n8n:5678';
const n8nBaseUrl = deriveBaseUrl(headers, fallbackBaseUrl);
const actionUrl = `${n8nBaseUrl}/webhook/clubspark-package-members-import-generate`;
const exampleNames = ['Aaron Mackintosh', 'Dylan Whybrow', 'Amy Palmer'].join('\n');
const html = `<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>ClubSpark Package Members Import</title><style>:root{color-scheme:light;--bg:#f7f8fc;--panel:#ffffff;--ink:#2e3d4e;--muted:#6b7785;--line:#e2e8f0;--accent:#509ee3;--accent-dark:#2f80d8;--soft:#f2f7fd;--button-soft:#eef2f7}*{box-sizing:border-box}body{margin:0;padding:24px;background:linear-gradient(180deg,#fbfcfe 0%,var(--bg) 100%);font-family:Lato,'Helvetica Neue',Arial,sans-serif;color:var(--ink)}.wrap{max-width:920px;margin:0 auto;display:grid;gap:20px}.panel{background:var(--panel);border:1px solid var(--line);border-radius:18px;box-shadow:0 18px 40px rgba(53,72,91,.08);padding:28px}h1{margin:0 0 8px;font-size:32px;line-height:1.05;letter-spacing:-.02em}.meta{margin:0;color:var(--muted);line-height:1.5}.callout{margin-top:16px;padding:14px 16px;border-radius:14px;background:var(--soft);border:1px solid var(--line)}form{display:grid;gap:16px;margin-top:20px}label{display:grid;gap:8px;font-weight:700}textarea,input[type=text]{width:100%;border:1px solid var(--line);border-radius:12px;padding:12px 14px;font:inherit;background:#fff;color:var(--ink)}textarea{min-height:320px;resize:vertical;line-height:1.45}.grid{display:grid;gap:16px;grid-template-columns:repeat(auto-fit,minmax(220px,1fr))}.button{display:inline-flex;align-items:center;justify-content:center;padding:12px 18px;border-radius:999px;text-decoration:none;font-weight:700;border:0;cursor:pointer;font:inherit;background:linear-gradient(135deg,var(--accent) 0%,var(--accent-dark) 100%);color:#fff;box-shadow:0 10px 24px rgba(80,158,227,.22)}code{font-family:'SFMono-Regular',Consolas,'Liberation Mono',Menlo,monospace}@media (max-width:720px){body{padding:14px}.panel{padding:18px}h1{font-size:28px}}</style></head><body><div class="wrap"><section class="panel"><h1>ClubSpark Package Members Import</h1><p class="meta">Generate an Excel workbook matching the junior package import template. The workflow looks up each named member in <code>raw_members</code>, resolves the main contact, and sets <code>PrimaryContactID</code> to that contact's ClubSpark identifier while also emitting distinct main contacts as their own workbook rows.</p><div class="callout">Enter member names separated by new lines or commas. The exported workbook uses the exact template columns from <code>PackageMembers-Junior-Template.xlsx</code>. <code>ContactID</code> and <code>PrimaryContactID</code> come from ClubSpark <code>Unique ID</code> values with square brackets removed. The result page shows which main contact was used for each member before download.</div><form method="POST" action="${escapeHtml(actionUrl)}"><label><span>Member names</span><textarea name="names" placeholder="One member name per line" required>${escapeHtml(exampleNames)}</textarea></label><div class="grid"><label><span>Default country</span><input type="text" name="default_country" value="United Kingdom"></label><label><span>File name prefix</span><input type="text" name="file_prefix" value="clubspark-package-members-import"></label></div><button class="button" type="submit">Generate Summary</button></form></section></div></body></html>`;
return [{ json: { html } }];

const request = $('Generate Import CSV Webhook').first()?.json ?? $input.first()?.json ?? {};
const body = request.body ?? request;
const clean = (value) => value === null || value === undefined ? '' : String(value).trim();
const collapse = (value) => clean(value).replace(/\s+/g, ' ');
const names = [];
const seen = new Set();
for (const part of String(body.names ?? '').replace(/\r/g, '').split(/[\n,;]+/)) {
  const name = collapse(part);
  if (!name) continue;
  const key = name.toLowerCase();
  if (seen.has(key)) continue;
  seen.add(key);
  names.push(name);
}
const filePrefix = clean(body.file_prefix) || 'clubspark-package-members-import';
const defaultCountry = clean(body.default_country) || 'United Kingdom';
const downloadFormat = clean(body.download_format || '').toLowerCase();
const stamp = new Date().toISOString().slice(0, 10).replace(/-/g, '');
const fileName = `${filePrefix}-${stamp}.xlsx`;
const errorMessage = !names.length ? 'Enter at least one member name.' : '';
return [{ json: { names, default_country: defaultCountry, file_name: fileName, file_prefix: filePrefix, download_format: downloadFormat, error_message: errorMessage } }];

const request = $('Resolve Generate Request').first().json ?? {};
const rows = $input.all().map((item) => item.json ?? {});
const headers = [
  'ContactID','PrimaryContactID','FirstName','LastName','EmailAddress','StartDate','ExpiryDate','Cost','Paid','GiftAid','Gender','BirthDate','HomeNumber','WorkNumber','MobileNumber','EmergencyPhoneNumber','PostCode','Address1','Address2','Address3','Town','County','Country','Occupation','DateJoinedVenue','MedicalHistory','Source','KeyPinNumber','TagsProvided'
];
const clean = (value) => value === null || value === undefined ? '' : String(value).trim();
const escapeHtml = (value) => String(value ?? '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/\"/g, '&quot;')
  .replace(/'/g, '&#39;');
const unresolved = request.names.filter((name, index) => !rows.some((row) => Number(row.input_order) === index + 1));
if (!rows.length || unresolved.length) {
  const missing = unresolved.length ? unresolved.join(', ') : request.names.join(', ');
  return [{ json: { error_message: `No current raw_members row was found for: ${missing}` } }];
}
const formatGender = (value) => {
  const raw = clean(value).toLowerCase();
  if (raw === 'male') return 'M';
  if (raw === 'female') return 'F';
  return clean(value);
};
const formatNumeric = (value) => {
  if (value === null || value === undefined || value === '') return '';
  const parsed = Number.parseFloat(String(value).replace(/[^0-9.-]+/g, ''));
  if (Number.isNaN(parsed)) return clean(value);
  return Number.isInteger(parsed) ? String(parsed) : String(parsed).replace(/\.0+$/, '').replace(/(\.\d*[1-9])0+$/, '$1');
};
const formatKeyPin = (value) => {
  const raw = clean(value);
  return raw === '[]' ? '' : raw;
};
const stripBrackets = (value) => clean(value).replace(/[\[\]]/g, '');
const defaultCountry = clean(request.default_country);
const ordered = [...rows].sort((a, b) => Number(a.input_order) - Number(b.input_order));
const output = [];
const missingIds = [];
const emittedPrimaryRows = new Set();
const buildExportRow = (row, prefix, contactId, primaryContactId, fallbackCountry) => ({
  ContactID: contactId,
  PrimaryContactID: primaryContactId,
  FirstName: clean(row[`${prefix}_first_name`]),
  LastName: clean(row[`${prefix}_last_name`]),
  EmailAddress: clean(row[`${prefix}_email`]),
  StartDate: clean(row[`${prefix}_start_date`]),
  ExpiryDate: clean(row[`${prefix}_expiry_date`]),
  Cost: formatNumeric(row[`${prefix}_cost`]),
  Paid: formatNumeric(row[`${prefix}_paid`]),
  GiftAid: clean(row[`${prefix}_gift_aid`]),
  Gender: formatGender(row[`${prefix}_gender`]),
  BirthDate: clean(row[`${prefix}_birth_date`]),
  HomeNumber: clean(row[`${prefix}_home_number`]),
  WorkNumber: clean(row[`${prefix}_work_number`]),
  MobileNumber: clean(row[`${prefix}_mobile_number`]),
  EmergencyPhoneNumber: clean(row[`${prefix}_emergency_phone_number`]),
  PostCode: clean(row[`${prefix}_postcode`]),
  Address1: clean(row[`${prefix}_address_1`]),
  Address2: clean(row[`${prefix}_address_2`]),
  Address3: clean(row[`${prefix}_address_3`]),
  Town: clean(row[`${prefix}_town`]),
  County: clean(row[`${prefix}_county`]),
  Country: clean(row[`${prefix}_country`]) || fallbackCountry,
  Occupation: clean(row[`${prefix}_occupation`]),
  DateJoinedVenue: clean(row[`${prefix}_date_joined_venue`]),
  MedicalHistory: clean(row[`${prefix}_medical_history`]),
  Source: clean(row[`${prefix}_source`]),
  KeyPinNumber: formatKeyPin(row[`${prefix}_key_pin_number`]),
  TagsProvided: clean(row[`${prefix}_tags_provided`]),
});
for (const row of ordered) {
  const hasDistinctPrimary = row.has_distinct_primary === true || row.has_distinct_primary === 'true' || row.has_distinct_primary === 't';
  const requestedName = clean(request.names[Number(row.input_order) - 1] || row.input_name || row.member_name);
  const matchedMember = clean(row.member_name || `${row.member_first_name || ''} ${row.member_last_name || ''}`);
  const memberContactId = stripBrackets(row.member_unique_id);
  const primaryContactId = hasDistinctPrimary ? stripBrackets(row.primary_unique_id) : memberContactId;
  if (!memberContactId) {
    missingIds.push(`${matchedMember || requestedName} (member Unique ID)`);
    continue;
  }
  if (hasDistinctPrimary && !primaryContactId) {
    missingIds.push(`${matchedMember || requestedName} (primary contact Unique ID)`);
    continue;
  }
  const primaryName = clean(row.primary_name || `${row.primary_first_name || ''} ${row.primary_last_name || ''}`) || matchedMember;
  const primaryEmail = hasDistinctPrimary ? clean(row.primary_email) : clean(row.member_email);
  if (hasDistinctPrimary && !emittedPrimaryRows.has(primaryContactId)) {
    const primaryRow = buildExportRow(row, 'primary', primaryContactId, primaryContactId, defaultCountry);
    output.push({
      json: {
        ...primaryRow,
        _rowType: 'primary',
        _requestedName: requestedName,
        _matchedMember: matchedMember,
        _primaryName: primaryName,
        _primaryEmail: primaryEmail,
        _primaryContactId: primaryContactId,
        _memberContactId: memberContactId,
        _relationship: 'Main contact row emitted',
        _fileName: request.file_name,
      },
    });
    emittedPrimaryRows.add(primaryContactId);
  }
  const memberRow = buildExportRow(row, 'member', memberContactId, primaryContactId, defaultCountry);
  output.push({
    json: {
      ...memberRow,
      _rowType: 'member',
      _requestedName: requestedName,
      _matchedMember: matchedMember,
      _primaryName: primaryName,
      _primaryEmail: primaryEmail,
      _primaryContactId: primaryContactId,
      _memberContactId: memberContactId,
      _relationship: hasDistinctPrimary ? 'Distinct main contact linked and exported' : 'Member used as own primary contact',
      _fileName: request.file_name,
    },
  });
}
if (missingIds.length) {
  return [{ json: { error_message: `Missing ClubSpark Unique ID for: ${missingIds.join(', ')}` } }];
}
return output;

const item = $input.first()?.json ?? {};
const message = item.error_message || 'Unable to build the ClubSpark import CSV.';
const escapeHtml = (value) => String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/\"/g, '&quot;').replace(/'/g, '&#39;');
const html = `<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>ClubSpark Import Failed</title><style>body{margin:0;padding:24px;background:#f7f8fc;font-family:Lato,'Helvetica Neue',Arial,sans-serif;color:#2e3d4e}.panel{max-width:760px;margin:0 auto;background:#fff;border:1px solid #e2e8f0;border-radius:18px;box-shadow:0 18px 40px rgba(53,72,91,.08);padding:28px}.button{display:inline-flex;align-items:center;justify-content:center;padding:12px 18px;border-radius:999px;text-decoration:none;font-weight:700;background:linear-gradient(135deg,#509ee3 0%,#2f80d8 100%);color:#fff}</style></head><body><div class="panel"><h1>ClubSpark Import Failed</h1><p>${escapeHtml(message)}</p><p><a class="button" href="javascript:history.back()">Back</a></p></div></body></html>`;
return [{ json: { html } }];

const rows = $input.all().map((item) => item.json ?? {});
const memberRows = rows.filter((row) => (row._rowType || 'member') === 'member');
const request = $('Resolve Generate Request').first().json ?? {};
const rawRequest = $('Generate Import CSV Webhook').first()?.json ?? {};
const headers = rawRequest.headers ?? {};
const clean = (value) => value === null || value === undefined ? '' : String(value).trim();
const escapeHtml = (value) => String(value ?? '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/\"/g, '&quot;')
  .replace(/'/g, '&#39;');
const deriveBaseUrl = (headers, fallback) => {
  const forwardedProto = clean(headers['x-forwarded-proto']);
  const forwardedHost = clean(headers['x-forwarded-host']);
  const host = forwardedHost || clean(headers.host);
  const forwardedPort = clean(headers['x-forwarded-port']);
  if (!host) return fallback;
  const proto = forwardedProto || 'http';
  let authority = host;
  if (forwardedPort && !authority.includes(':')) {
    const isDefaultPort = (proto === 'http' && forwardedPort === '80') || (proto === 'https' && forwardedPort === '443');
    if (!isDefaultPort) authority = `${authority}:${forwardedPort}`;
  }
  return `${proto}://${authority}`;
};
const n8nBaseUrl = deriveBaseUrl(headers, 'http://n8n:5678');
const actionUrl = `${n8nBaseUrl}/webhook/clubspark-package-members-import-generate`;
const summaryRowsHtml = memberRows.map((row) => `<tr><td>${escapeHtml(row._requestedName)}</td><td>${escapeHtml(row._matchedMember)}</td><td>${escapeHtml(row._primaryName)}</td><td>${escapeHtml(row._primaryEmail)}</td><td>${escapeHtml(row._primaryContactId)}</td><td>${escapeHtml(row._memberContactId)}</td><td>${escapeHtml(row._relationship)}</td></tr>`).join('');
const distinctMainContacts = new Set(memberRows.map((row) => row._primaryContactId).filter(Boolean)).size;
const workbookRows = rows.length;
const html = `<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>ClubSpark Import Ready</title><style>:root{color-scheme:light;--bg:#f7f8fc;--panel:#ffffff;--ink:#2e3d4e;--muted:#6b7785;--line:#e2e8f0;--accent:#509ee3;--accent-dark:#2f80d8;--soft:#f2f7fd;--good:#eff8f2}*{box-sizing:border-box}body{margin:0;padding:24px;background:linear-gradient(180deg,#fbfcfe 0%,var(--bg) 100%);font-family:Lato,'Helvetica Neue',Arial,sans-serif;color:var(--ink)}.wrap{max-width:1160px;margin:0 auto;display:grid;gap:20px}.panel{background:var(--panel);border:1px solid var(--line);border-radius:18px;box-shadow:0 18px 40px rgba(53,72,91,.08);padding:28px}.hero{display:flex;gap:18px;justify-content:space-between;align-items:flex-start;flex-wrap:wrap}.hero h1{margin:0 0 8px;font-size:32px;line-height:1.05;letter-spacing:-.02em}.meta{margin:0;color:var(--muted);line-height:1.5}.stats{display:grid;gap:12px;grid-template-columns:repeat(auto-fit,minmax(160px,1fr));margin-top:18px}.stat{padding:16px;border-radius:14px;background:var(--soft);border:1px solid var(--line)}.stat strong{display:block;font-size:28px;line-height:1.1}.actions{display:flex;gap:12px;flex-wrap:wrap}.button{display:inline-flex;align-items:center;justify-content:center;padding:12px 18px;border-radius:999px;text-decoration:none;font-weight:700;border:0;cursor:pointer;font:inherit;background:linear-gradient(135deg,var(--accent) 0%,var(--accent-dark) 100%);color:#fff;box-shadow:0 10px 24px rgba(80,158,227,.22)}.button.secondary{background:#eef2f7;color:var(--ink);box-shadow:none}.download-form{display:inline-flex}.download-form input{display:none}.callout{padding:14px 16px;border-radius:14px;background:var(--good);border:1px solid #dcefe4}.table-wrap{overflow:auto;border:1px solid var(--line);border-radius:16px}.summary-table{width:100%;border-collapse:collapse;min-width:860px}.summary-table th,.summary-table td{padding:12px 14px;border-bottom:1px solid var(--line);text-align:left;vertical-align:top}.summary-table th{background:#f8fafc;font-size:13px;letter-spacing:.02em;text-transform:uppercase;color:var(--muted)}.summary-table tr:last-child td{border-bottom:0}.mono{font-family:'SFMono-Regular',Consolas,'Liberation Mono',Menlo,monospace}code{font-family:'SFMono-Regular',Consolas,'Liberation Mono',Menlo,monospace}@media (max-width:720px){body{padding:14px}.panel{padding:18px}.hero h1{font-size:28px}}</style></head><body><div class="wrap"><section class="panel"><div class="hero"><div><h1>ClubSpark Import Ready</h1><p class="meta">Review the resolved main contacts below, then download the real Excel workbook. The workbook emits distinct main contacts as their own rows before the linked member rows, while still using ClubSpark Unique IDs without square brackets for <code>ContactID</code> and <code>PrimaryContactID</code>.</p></div><div class="actions"><form class="download-form" method="POST" action="${escapeHtml(actionUrl)}"><input type="hidden" name="names" value="${escapeHtml(request.names.join('\n'))}"><input type="hidden" name="default_country" value="${escapeHtml(request.default_country)}"><input type="hidden" name="file_prefix" value="${escapeHtml(request.file_prefix)}"><input type="hidden" name="download_format" value="xlsx"><button class="button" type="submit">Download XLSX</button></form><a class="button secondary" href="javascript:history.back()">Back</a></div></div><div class="stats"><div class="stat"><span>Requested members</span><strong>${escapeHtml(String(memberRows.length))}</strong></div><div class="stat"><span>Distinct main contacts</span><strong>${escapeHtml(String(distinctMainContacts))}</strong></div><div class="stat"><span>Total workbook rows</span><strong>${escapeHtml(String(workbookRows))}</strong></div></div><div class="callout">The download is an actual <span class="mono">.xlsx</span> workbook generated by n8n. It uses the template column order exactly and now includes explicit main-contact rows when a member has a distinct primary contact.</div></section><section class="panel"><h2>Main Contact Summary</h2><div class="table-wrap"><table class="summary-table"><thead><tr><th>Requested name</th><th>Matched member</th><th>Main contact used</th><th>Main contact email</th><th>PrimaryContactID</th><th>Member ContactID</th><th>Resolution</th></tr></thead><tbody>${summaryRowsHtml}</tbody></table></div></section></div></body></html>`;
return [{ json: { html } }];

const headers = [
  'ContactID','PrimaryContactID','FirstName','LastName','EmailAddress','StartDate','ExpiryDate','Cost','Paid','GiftAid','Gender','BirthDate','HomeNumber','WorkNumber','MobileNumber','EmergencyPhoneNumber','PostCode','Address1','Address2','Address3','Town','County','Country','Occupation','DateJoinedVenue','MedicalHistory','Source','KeyPinNumber','TagsProvided'
];
return $input.all().map((item) => {
  const row = item.json ?? {};
  const exportRow = {};
  for (const header of headers) exportRow[header] = row[header] ?? '';
  return { json: exportRow };
});
